using System;
using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.UI;

/// <summary>
/// Secção "Diário" do Menu de Pausa (Tarefa #8) — diário de viagem da Íris
/// (desenhos, folhas, marcas de pata).
///
/// Lista (esquerda), agrupada por "Região sugerida" (MissionData.suggestedWorld),
/// na ordem em que as missões aparecem em <see cref="allMissions"/>:
/// - "●" — missão iniciada e ainda não concluída.
/// - "○" — missão ainda não iniciada, mas marcada com
///   <see cref="MissionData.showInJournalBeforeStart"/> (rumor/conversa ouvida).
/// - Ícone de flor/folha/estrela (<see cref="completedIcon"/>) — missão concluída,
///   em vez de qualquer marcador.
///
/// Missões não iniciadas e sem "showInJournalBeforeStart" NÃO aparecem.
///
/// Depois das missões, se houver pelo menos um rumor ouvido
/// (<see cref="allRumors"/> + JournalManager — Sistema de Pistas/Rumores), é
/// mostrado um cabeçalho "RUMORES" seguido de uma linha por rumor ouvido, com
/// um ícone de "Check" (<see cref="rumorFoundIcon"/>) junto aos já marcados
/// como encontrados (Action_MarkRumorFound). Os rumores NUNCA desaparecem da
/// lista.
///
/// Detalhe (centro), para a missão seleccionada:
/// - Título (MissionData.displayName)
/// - "Quem pediu: ..." (MissionData.requestedBy — pessoa + local)
/// - "O que ele precisa: ..." (MissionData.whatIsNeeded)
/// - "Tarefas" (sub-lista, <see cref="tasksContainer"/>): tarefas "visíveis"
///   (concluídas OU activas — ver MissionManager.IsTaskActive) da missão, cada
///   uma com um ícone de "Check" (<see cref="taskCompletedIcon"/>) se já
///   concluída. Tarefas não-lineares: podem aparecer VÁRIAS tarefas activas em
///   simultâneo (sem check); tarefas ainda bloqueadas por dependências
///   (MissionTask.dependsOnTaskIds) não aparecem. Ao concluir a última tarefa
///   em falta, a missão conclui-se automaticamente (MissionManager).
/// - "Última pista: "..."" (MissionData.lastHint — citação exacta)
/// - "Região sugerida: ..." (MissionData.suggestedWorld.displayName)
/// - "Pistas" (sub-lista, <see cref="cluesContainer"/>): pistas já obtidas
///   desta missão (MissionData.clues + PlayerProgress.obtainedClueIds).
///   Confirmar numa pista reabre-a em ecrã inteiro (FullscreenImageUI).
///
/// Ou, para um rumor seleccionado (secção "Rumores"):
/// - Título (rumor.title, ou o início de rumor.text se vazio)
/// - "O que ele precisa" reaproveitado para mostrar rumor.text
/// - "Região sugerida: ..." (rumor.region.displayName, se atribuída)
/// - Confirmar reabre a imagem do rumor em ecrã inteiro, se houver.
///
/// IMPORTANTE (distinção da spec): o Diário é memória NARRATIVA — quem pediu o
/// quê, a última conversa relevante, em que mundo/área a procura deve
/// acontecer ("Região sugerida"). NUNCA mostra seta/marcador/"seguir
/// missão"/distância/bússola/PDI — isso é "Área Atual" (Tarefa #7), que é
/// exploração física do lugar onde o jogador está.
///
/// Montagem no Editor:
/// - "allMissions": todas as MissionData do jogo, na ordem desejada de
///   agrupamento (mudanças de "suggestedWorld" consecutivas criam um novo
///   cabeçalho de mundo).
/// - "missionRowPrefab": prefab com <see cref="DiaryMissionRow"/> + um
///   Selectable (ex: Button) para navegação D-pad/teclado.
/// - "worldHeaderPrefab": TMP_Text simples (ex: "BOSQUE DE BRUMA"), também
///   reutilizado para o cabeçalho "RUMORES".
/// - "allRumors": todos os RumorData do jogo, na ordem desejada da secção
///   "Rumores" (apenas os já ouvidos são mostrados).
/// - "rumorRowPrefab": prefab com <see cref="DiaryRumorRow"/> + Selectable.
/// - "clueRowPrefab": prefab com <see cref="DiaryClueRow"/> + Selectable,
///   instanciado dentro de "cluesContainer" para cada pista obtida da missão
///   seleccionada.
/// - "taskRowPrefab": prefab com <see cref="DiaryTaskRow"/>, instanciado dentro
///   de "tasksContainer" para cada tarefa "visível" (concluída ou activa) da
///   missão seleccionada — ver <see cref="RefreshTasks"/>.
/// </summary>
public class DiarySectionUI : MonoBehaviour, IPauseMenuSection
{
    [Header("Framework")]
    [SerializeField] private GameObject root;

    [Header("Missões (ordem define o agrupamento por mundo)")]
    [SerializeField] private List<MissionData> allMissions = new List<MissionData>();

    [Header("Lista de Missões (esquerda)")]
    [SerializeField] private Transform listContainer;
    [SerializeField] private TMP_Text worldHeaderPrefab;
    [SerializeField] private DiaryMissionRow missionRowPrefab;

    [Header("Marcadores de Estado")]
    [Tooltip("Marcador para missões iniciadas e ainda não concluídas.")]
    [SerializeField] private string activeMarker = "●";

    [Tooltip("Marcador para missões ainda não iniciadas mas conhecidas (showInJournalBeforeStart).")]
    [SerializeField] private string inactiveMarker = "○";

    [Tooltip("Ícone (flor/folha/estrela) mostrado em vez do marcador quando a missão está concluída.")]
    [SerializeField] private Sprite completedIcon;

    [Header("Detalhe da Missão (centro)")]
    [SerializeField] private GameObject detailRoot;
    [SerializeField] private TMP_Text titleText;

    [SerializeField] private TMP_Text requestedByText;
    [SerializeField] private string requestedByFormat = "Quem pediu: {0}";

    [SerializeField] private TMP_Text whatIsNeededText;
    [SerializeField] private string whatIsNeededFormat = "O que ele precisa: {0}";

    [Header("Tarefas (Diário — tarefas não-lineares)")]
    [Tooltip("Container onde são instanciadas as linhas de Tarefas (DiaryTaskRow) \"visíveis\" (concluídas ou activas — ver MissionManager.IsTaskActive) da missão seleccionada. Normalmente dentro do painel de detalhe.")]
    [SerializeField] private Transform tasksContainer;

    [SerializeField] private DiaryTaskRow taskRowPrefab;

    [Tooltip("Ícone de \"Check\" mostrado junto a tarefas já concluídas.")]
    [SerializeField] private Sprite taskCompletedIcon;

    [Tooltip("GameObject opcional (ex: cabeçalho \"Tarefas\") activado/desactivado conforme a missão seleccionada tenha ou não tarefas visíveis.")]
    [SerializeField] private GameObject tasksHeader;

    [SerializeField] private TMP_Text lastHintText;
    [SerializeField] private string lastHintFormat = "Última pista: “{0}”";

    [SerializeField] private TMP_Text suggestedRegionText;
    [SerializeField] private string suggestedRegionFormat = "Região sugerida: {0}";

    [Header("Pistas (Diário — Sistema de Pistas/Rumores)")]
    [Tooltip("Container onde são instanciadas as linhas de Pistas (DiaryClueRow) já obtidas da missão seleccionada. Normalmente dentro do painel de detalhe.")]
    [SerializeField] private Transform cluesContainer;

    [SerializeField] private DiaryClueRow clueRowPrefab;

    [Tooltip("GameObject opcional (ex: cabeçalho \"Pistas\") activado/desactivado conforme a missão seleccionada tenha ou não pistas obtidas.")]
    [SerializeField] private GameObject cluesHeader;

    [Header("Rumores (secção global — Sistema de Pistas/Rumores)")]
    [Tooltip("Todos os rumores do jogo, na ordem desejada (apenas os já ouvidos aparecem no Diário).")]
    [SerializeField] private List<RumorData> allRumors = new List<RumorData>();

    [SerializeField] private DiaryRumorRow rumorRowPrefab;

    [Tooltip("Ícone de \"Check\" mostrado junto a rumores já marcados como encontrados (Action_MarkRumorFound) — não os remove da lista.")]
    [SerializeField] private Sprite rumorFoundIcon;

    [Tooltip("Texto do cabeçalho da secção de rumores (reutiliza \"worldHeaderPrefab\").")]
    [SerializeField] private string rumorsHeaderText = "RUMORES";

    [Header("Diário Vazio")]
    [SerializeField] private GameObject emptyState;
    [SerializeField] private string emptyText = "O diário está vazio.";

    private readonly List<GameObject> spawnedEntries = new List<GameObject>();
    private readonly List<GameObject> spawnedClueEntries = new List<GameObject>();
    private readonly List<GameObject> spawnedTaskEntries = new List<GameObject>();

    private MissionData selectedMission;
    private RumorData selectedRumor;

    public string SectionName => "DIÁRIO";
    public GameObject Root => root != null ? root : gameObject;

    public void Refresh()
    {
        ClearSpawned();

        var mm = MissionManager.Instance;
        var visible = new List<MissionData>();

        foreach (var mission in allMissions)
        {
            if (mission == null) continue;

            bool started = mm != null && mm.IsMissionStarted(mission);
            if (started || mission.showInJournalBeforeStart) visible.Add(mission);
        }

        var heardRumors = GetHeardRumors();

        if (visible.Count == 0 && heardRumors.Count == 0)
        {
            if (emptyState != null)
            {
                emptyState.SetActive(true);

                var emptyTextComponent = emptyState.GetComponentInChildren<TMP_Text>();
                if (emptyTextComponent != null) emptyTextComponent.text = emptyText;
            }

            if (detailRoot != null) detailRoot.SetActive(false);
            selectedMission = null;
            selectedRumor = null;
            return;
        }

        if (emptyState != null) emptyState.SetActive(false);
        if (detailRoot != null) detailRoot.SetActive(true);

        MissionData missionToSelect = null;
        RumorData rumorToSelect = null;

        if (visible.Count > 0)
            missionToSelect = (selectedMission != null && visible.Contains(selectedMission)) ? selectedMission : visible[0];
        else if (heardRumors.Count > 0)
            rumorToSelect = (selectedRumor != null && heardRumors.Contains(selectedRumor)) ? selectedRumor : heardRumors[0];

        WorldData currentWorld = null;
        bool firstWorld = true;
        DiaryMissionRow selectedMissionRow = null;
        DiaryRumorRow selectedRumorRow = null;

        foreach (var mission in visible)
        {
            if (firstWorld || mission.suggestedWorld != currentWorld)
            {
                currentWorld = mission.suggestedWorld;
                firstWorld = false;
                SpawnHeader(currentWorld != null ? currentWorld.displayName.ToUpperInvariant() : string.Empty);
            }

            var row = SpawnMissionRow(mission, mm);
            if (row != null && mission == missionToSelect) selectedMissionRow = row;
        }

        if (heardRumors.Count > 0)
        {
            SpawnHeader(rumorsHeaderText);

            foreach (var rumor in heardRumors)
            {
                var row = SpawnRumorRow(rumor);
                if (row != null && rumor == rumorToSelect) selectedRumorRow = row;
            }
        }

        if (missionToSelect != null) ShowDetails(missionToSelect);
        else ShowRumorDetails(rumorToSelect);

        GameObject toFocus = selectedMissionRow != null ? selectedMissionRow.gameObject
            : selectedRumorRow != null ? selectedRumorRow.gameObject : null;

        if (toFocus != null && EventSystem.current != null)
            EventSystem.current.SetSelectedGameObject(toFocus);
    }

    public void OnHide()
    {
        // Sem estado próprio a limpar — Refresh() repõe tudo na próxima vez.
    }

    // ---------------- Lista ----------------

    private void SpawnHeader(string text)
    {
        if (worldHeaderPrefab == null || listContainer == null) return;

        var header = Instantiate(worldHeaderPrefab, listContainer);
        header.gameObject.SetActive(true);
        header.text = text;
        spawnedEntries.Add(header.gameObject);
    }

    private DiaryMissionRow SpawnMissionRow(MissionData mission, MissionManager mm)
    {
        if (missionRowPrefab == null || listContainer == null) return null;

        var row = Instantiate(missionRowPrefab, listContainer);
        row.gameObject.SetActive(true);

        bool completed = mm != null && mm.IsMissionCompleted(mission);
        bool started = mm != null && mm.IsMissionStarted(mission);
        string marker = started ? activeMarker : inactiveMarker;

        row.Setup(mission, completed, marker, completedIcon, ShowDetails);
        spawnedEntries.Add(row.gameObject);
        return row;
    }

    // ---------------- Rumores ----------------

    /// <summary>Devolve, na ordem de "allRumors", os rumores já ouvidos (PlayerProgress.heardRumorIds via JournalManager).</summary>
    private List<RumorData> GetHeardRumors()
    {
        var result = new List<RumorData>();

        var journal = JournalManager.Instance;
        if (journal == null) return result;

        foreach (var rumor in allRumors)
            if (rumor != null && journal.HasHeardRumor(rumor)) result.Add(rumor);

        return result;
    }

    private DiaryRumorRow SpawnRumorRow(RumorData rumor)
    {
        if (rumorRowPrefab == null || listContainer == null) return null;

        var row = Instantiate(rumorRowPrefab, listContainer);
        row.gameObject.SetActive(true);

        bool found = JournalManager.Instance != null && JournalManager.Instance.IsRumorFound(rumor);
        row.Setup(rumor, found, rumorFoundIcon, ShowRumorDetails, ShowRumorFullscreen);

        spawnedEntries.Add(row.gameObject);
        return row;
    }

    /// <summary>Reabre a imagem do rumor em ecrã inteiro (FullscreenImageUI), se houver ("Confirmar" numa linha de Rumor — DiaryRumorRow.OnSubmit).</summary>
    private void ShowRumorFullscreen(RumorData rumor)
    {
        if (rumor == null || rumor.image == null || FullscreenImageUI.Instance == null) return;
        StartCoroutine(FullscreenImageUI.Instance.Show(rumor.image, rumor.title, rumor.text));
    }

    // ---------------- Pistas ----------------

    /// <summary>Repõe a sub-lista de Pistas (cluesContainer) com as pistas já obtidas da missão seleccionada.</summary>
    private void RefreshClues(MissionData mission)
    {
        ClearClueRows();

        bool any = false;

        if (cluesContainer != null && clueRowPrefab != null && mission != null && mission.clues != null)
        {
            var journal = JournalManager.Instance;

            foreach (var clue in mission.clues)
            {
                if (clue == null || string.IsNullOrEmpty(clue.clueId)) continue;
                if (journal == null || !journal.HasClue(mission, clue.clueId)) continue;

                var row = Instantiate(clueRowPrefab, cluesContainer);
                row.gameObject.SetActive(true);
                row.Setup(clue, ShowClueFullscreen);

                spawnedClueEntries.Add(row.gameObject);
                any = true;
            }
        }

        if (cluesHeader != null) cluesHeader.SetActive(any);
    }

    /// <summary>Reabre uma pista de missão em ecrã inteiro (FullscreenImageUI), "Confirmar" numa linha de Pista — DiaryClueRow.OnSubmit).</summary>
    private void ShowClueFullscreen(MissionClue clue)
    {
        if (clue == null || FullscreenImageUI.Instance == null) return;
        StartCoroutine(FullscreenImageUI.Instance.Show(clue.image, clue.title, clue.description));
    }

    private void ClearClueRows()
    {
        foreach (var go in spawnedClueEntries)
            if (go != null) Destroy(go);

        spawnedClueEntries.Clear();
    }

    // ---------------- Tarefas (não-lineares) ----------------

    /// <summary>
    /// Repõe a sub-lista de Tarefas (tasksContainer) com as tarefas "visíveis"
    /// da missão seleccionada: concluídas (com <see cref="taskCompletedIcon"/>)
    /// OU activas (ver MissionManager.IsTaskActive — dependências cumpridas,
    /// sem check). Tarefas ainda bloqueadas (dependências não cumpridas) não
    /// aparecem. Pode haver várias tarefas activas em simultâneo.
    /// </summary>
    private void RefreshTasks(MissionData mission)
    {
        ClearTaskRows();

        bool any = false;

        if (tasksContainer != null && taskRowPrefab != null && mission != null && mission.tasks != null)
        {
            var mm = MissionManager.Instance;

            foreach (var task in mission.tasks)
            {
                if (task == null || string.IsNullOrEmpty(task.description)) continue;

                bool completed = mm != null && mm.IsTaskCompleted(mission, task);
                bool active = mm != null && mm.IsTaskActive(mission, task);

                if (!completed && !active) continue; // ainda bloqueada — não mostra

                var row = Instantiate(taskRowPrefab, tasksContainer);
                row.gameObject.SetActive(true);
                row.Setup(task, completed, taskCompletedIcon);

                spawnedTaskEntries.Add(row.gameObject);
                any = true;
            }
        }

        if (tasksHeader != null) tasksHeader.SetActive(any);
    }

    private void ClearTaskRows()
    {
        foreach (var go in spawnedTaskEntries)
            if (go != null) Destroy(go);

        spawnedTaskEntries.Clear();
    }

    // ---------------- Detalhe ----------------

    private void ShowDetails(MissionData mission)
    {
        selectedMission = mission;
        selectedRumor = null;
        if (mission == null) return;

        if (titleText != null) titleText.text = mission.displayName;

        if (requestedByText != null)
        {
            requestedByText.gameObject.SetActive(true);
            requestedByText.text = string.Format(requestedByFormat, mission.requestedBy);
        }

        if (whatIsNeededText != null)
        {
            whatIsNeededText.gameObject.SetActive(true);
            whatIsNeededText.text = string.Format(whatIsNeededFormat, mission.whatIsNeeded);
        }

        if (lastHintText != null)
        {
            lastHintText.gameObject.SetActive(true);
            lastHintText.text = string.Format(lastHintFormat, mission.lastHint);
        }

        RefreshTasks(mission);

        if (suggestedRegionText != null)
        {
            suggestedRegionText.gameObject.SetActive(true);

            string region = mission.suggestedWorld != null ? mission.suggestedWorld.displayName : string.Empty;
            suggestedRegionText.text = string.Format(suggestedRegionFormat, region);
        }

        RefreshClues(mission);
    }

    /// <summary>
    /// Mostra os detalhes de um Rumor no painel central, no lugar de uma
    /// missão — reaproveita "whatIsNeededText" para o texto do rumor e
    /// "suggestedRegionText" para a região associada (se houver). Esconde os
    /// campos exclusivos de missão (Quem pediu/Tarefas/Última pista) e as
    /// sub-listas de Pistas e Tarefas.
    /// </summary>
    private void ShowRumorDetails(RumorData rumor)
    {
        selectedMission = null;
        selectedRumor = rumor;

        ClearClueRows();
        if (cluesHeader != null) cluesHeader.SetActive(false);

        ClearTaskRows();
        if (tasksHeader != null) tasksHeader.SetActive(false);

        if (rumor == null) return;

        if (titleText != null)
            titleText.text = !string.IsNullOrEmpty(rumor.title) ? rumor.title : rumor.text;

        if (requestedByText != null) requestedByText.gameObject.SetActive(false);
        if (lastHintText != null) lastHintText.gameObject.SetActive(false);

        if (whatIsNeededText != null)
        {
            bool hasText = !string.IsNullOrEmpty(rumor.text);
            whatIsNeededText.gameObject.SetActive(hasText);
            whatIsNeededText.text = rumor.text;
        }

        if (suggestedRegionText != null)
        {
            if (rumor.region != null)
            {
                suggestedRegionText.gameObject.SetActive(true);
                suggestedRegionText.text = string.Format(suggestedRegionFormat, rumor.region.displayName);
            }
            else
            {
                suggestedRegionText.gameObject.SetActive(false);
            }
        }
    }

    private void ClearSpawned()
    {
        foreach (var go in spawnedEntries)
            if (go != null) Destroy(go);

        spawnedEntries.Clear();

        ClearClueRows();
        ClearTaskRows();
    }
}

/// <summary>
/// Linha de missão na lista do Diário (DiarySectionUI). Mostra o nome da
/// missão e, à esquerda, o marcador "●"/"○" ou — se concluída — o ícone de
/// flor/folha/estrela. Implementa <see cref="ISelectHandler"/> para que a
/// navegação por D-pad/teclado (Selectable.Navigation) actualize o painel de
/// detalhe ao focar a linha.
///
/// Requer um Selectable (ex: Button) no mesmo GameObject para participar da
/// navegação do EventSystem.
/// </summary>
public class DiaryMissionRow : MonoBehaviour, ISelectHandler
{
    [SerializeField] private TMP_Text nameText;
    [SerializeField] private TMP_Text markerText;
    [SerializeField] private Image completedIconImage;

    private Action<MissionData> onSelected;

    public MissionData Mission { get; private set; }

    public void Setup(MissionData mission, bool completed, string marker, Sprite completedIcon, Action<MissionData> onSelected)
    {
        Mission = mission;
        this.onSelected = onSelected;

        if (nameText != null) nameText.text = mission.displayName;

        if (completed)
        {
            if (markerText != null) markerText.gameObject.SetActive(false);

            if (completedIconImage != null)
            {
                completedIconImage.gameObject.SetActive(true);
                completedIconImage.sprite = completedIcon;
                completedIconImage.enabled = completedIcon != null;
            }
        }
        else
        {
            if (markerText != null)
            {
                markerText.gameObject.SetActive(true);
                markerText.text = marker;
            }

            if (completedIconImage != null) completedIconImage.gameObject.SetActive(false);
        }
    }

    public void OnSelect(BaseEventData eventData)
    {
        onSelected?.Invoke(Mission);
    }
}

/// <summary>
/// Linha de Rumor na secção global "Rumores" do Diário (DiarySectionUI —
/// Sistema de Pistas/Rumores). Mostra o título do rumor e, opcionalmente, um
/// ícone de "Check" se já tiver sido marcado como "encontrado"
/// (Action_MarkRumorFound) — sem nunca ser removido da lista.
///
/// Ao ser seleccionada (D-pad/teclado/rato — <see cref="ISelectHandler"/>),
/// mostra os detalhes do rumor no painel central (ShowRumorDetails). Ao
/// confirmar (<see cref="ISubmitHandler"/> — mesmo botão Confirmar/Interagir),
/// reabre a imagem do rumor em ecrã inteiro, se houver.
///
/// Requer um Selectable (ex: Button) no mesmo GameObject para participar da
/// navegação do EventSystem.
/// </summary>
public class DiaryRumorRow : MonoBehaviour, ISelectHandler, ISubmitHandler
{
    [SerializeField] private TMP_Text titleText;
    [SerializeField] private Image checkIcon;

    private Action<RumorData> onSelected;
    private Action<RumorData> onSubmit;

    public RumorData Rumor { get; private set; }

    public void Setup(RumorData rumor, bool found, Sprite foundIcon, Action<RumorData> onSelected, Action<RumorData> onSubmit)
    {
        Rumor = rumor;
        this.onSelected = onSelected;
        this.onSubmit = onSubmit;

        if (titleText != null)
            titleText.text = rumor != null && !string.IsNullOrEmpty(rumor.title) ? rumor.title : rumor?.text;

        if (checkIcon != null)
        {
            checkIcon.gameObject.SetActive(found);
            checkIcon.sprite = foundIcon;
            checkIcon.enabled = found && foundIcon != null;
        }
    }

    public void OnSelect(BaseEventData eventData)
    {
        onSelected?.Invoke(Rumor);
    }

    public void OnSubmit(BaseEventData eventData)
    {
        onSubmit?.Invoke(Rumor);
    }
}

/// <summary>
/// Linha de Pista (MissionClue) na sub-lista "Pistas" da missão seleccionada
/// no Diário (DiarySectionUI — Sistema de Pistas/Rumores). Mostra o título da
/// pista; ao confirmar (<see cref="ISubmitHandler"/> — botão
/// Confirmar/Interagir), reabre a fotografia/descrição em ecrã inteiro
/// (FullscreenImageUI), tal como quando foi obtida pela primeira vez.
///
/// Requer um Selectable (ex: Button) no mesmo GameObject para participar da
/// navegação do EventSystem.
/// </summary>
public class DiaryClueRow : MonoBehaviour, ISubmitHandler
{
    [SerializeField] private TMP_Text titleText;

    private Action<MissionClue> onSubmit;

    public MissionClue Clue { get; private set; }

    public void Setup(MissionClue clue, Action<MissionClue> onSubmit)
    {
        Clue = clue;
        this.onSubmit = onSubmit;

        if (titleText != null)
            titleText.text = clue != null && !string.IsNullOrEmpty(clue.title) ? clue.title : clue?.description;
    }

    public void OnSubmit(BaseEventData eventData)
    {
        onSubmit?.Invoke(Clue);
    }
}

/// <summary>
/// Linha de Tarefa na sub-lista "Tarefas" da missão seleccionada no Diário
/// (DiarySectionUI.RefreshTasks — Sistema de Missões, tarefas não-lineares).
/// Mostra a descrição da tarefa e, se já estiver concluída, um ícone de "Check"
/// (<see cref="checkIcon"/>). Tarefas activas (ainda não concluídas, mas com
/// dependências cumpridas) aparecem sem check. Tarefas ainda bloqueadas
/// (dependências não cumpridas) nunca chegam a ser instanciadas.
///
/// Apenas informativa — não precisa de Selectable nem de navegação D-pad.
/// </summary>
public class DiaryTaskRow : MonoBehaviour
{
    [SerializeField] private TMP_Text descriptionText;
    [SerializeField] private Image checkIcon;

    public MissionTask Task { get; private set; }

    public void Setup(MissionTask task, bool completed, Sprite completedIcon)
    {
        Task = task;

